package cn.org.starpivot.api.mall.cart;import cn.org.starpivot.api.fallback.CartInternalClientFallbackFactory;import cn.org.starpivot.api.mall.promotion.dto.CouponTrialItemDto;import cn.org.starpivot.common.domain.Result;import org.springframework.cloud.openfeign.FeignClient;import org.springframework.web.bind.annotation.GetMapping;import org.springframework.web.bind.annotation.PathVariable;import java.util.List;/** * 购物车内部接口（供营销 BFF 优惠券试算拉取勾选商品）。 */@FeignClient(        name = "starpivot-mall-order",        contextId = "cartInternalClient",        path = "/api/${starpivot.api.version:v1}",        fallbackFactory = CartInternalClientFallbackFactory.class)public interface CartInternalClient {    @GetMapping("/internal/mall/cart/{memberId}/checked-items")    Result<List<CouponTrialItemDto>> listCheckedCartItems(@PathVariable("memberId") Long memberId);}